import { useAppDispatch, useAppSelector } from "../app/store/hooks/reduxHooks";

import {
  fetchCart,
  removeCartItem,
  buyCart,
} from "../app/store/thunks/cartThunks";

function CartUI () {
  return (
    <div id="content">
      <h2>–ö–ĺ—Ä–∑–ł–Ĺ–į</h2>

      {(!cart.items || cart.items.length === 0) && (
        <p>–ö–ĺ—Ä–∑–ł–Ĺ–į –Ņ—É—Ā—ā–į</p>
      )}

      {cart.items?.map((item) => (
        <div key={item.id}>
          <p>
            {item.game?.title || item.item?.title} ‚ÄĒ{" "}
            {item.game?.price || item.item?.price} ‚āĹ
          </p>

          <button onClick={() => handleRemove(item.id)}>
            –£–ī–į–Ľ–ł—ā—Ć
          </button>
        </div>
      ))}

      <h3>–ė—ā–ĺ–≥–ĺ: {cart?.total ?? 0} ‚āĹ</h3>

      <button onClick={handleBuy}>
        –ö—É–Ņ–ł—ā—Ć
      </button>
    </div>
)
}

export default CartUI;
